// Stage 1: Validate input
// Webhook v2 nests the POST payload under $json.body
const raw = $input.first().json;
const input = raw.body || raw;

const question = (input.question || '').trim();
if (!question) {
  throw new Error('Question is required. Send JSON: {"question": "..."}');
}

return {
  question: question,
  docId: input.docId || 'doc-' + Date.now(),
  receivedAt: new Date().toISOString()
};

// Stage 2: Embed query via LM Studio (OpenAI-compatible API)
// LM Studio default endpoint: http://127.0.0.1:1234
// If n8n runs in Docker, use http://host.docker.internal:1234 instead.
const LM_STUDIO_URL = 'http://127.0.0.1:1234';
const EMBED_MODEL = 'text-embedding-qwen3-embedding-8b';

const question = $input.first().json.question;

let res;
try {
  res = await this.helpers.httpRequest({
    method: 'POST',
    url: `${LM_STUDIO_URL}/v1/embeddings`,
    body: { model: EMBED_MODEL, input: question },
    json: true,
    timeout: 60000
  });
} catch (error) {
  throw new Error(`LM Studio embedding call failed: ${error.message}. Check LM Studio is running on ${LM_STUDIO_URL} with '${EMBED_MODEL}' loaded (Developer tab > Server running).`);
}

const embedding = res && res.data && res.data[0] && res.data[0].embedding;
if (!embedding || embedding.length === 0) {
  throw new Error(`Embedding response was empty. Verify model id '${EMBED_MODEL}' matches exactly what LM Studio shows under loaded models.`);
}

return {
  question: question,
  embedding: embedding,
  embeddingModel: EMBED_MODEL,
  embeddingDimension: embedding.length
};

// Stage 3: Vector retrieval (mock for demo)
// In production: replace with a Qdrant search using $json.embedding.
// The real embedding IS generated upstream, so swapping this node
// for a Qdrant query is the only change needed to go live.
const { question, embedding, embeddingModel, embeddingDimension } = $input.first().json;

const mockDocuments = [
  {
    chunkId: 1,
    similarity: 0.92,
    text: 'Architecture decisions shape system outcomes. Design patterns, scalability constraints, and deployment environments all influence technical choices. Microservices enable independent scaling but increase operational complexity.'
  },
  {
    chunkId: 2,
    similarity: 0.87,
    text: 'Automation frameworks reduce manual effort and improve consistency. Task orchestration, workflow triggers, and error handling are critical components. Event-driven architecture allows real-time processing at scale.'
  },
  {
    chunkId: 3,
    similarity: 0.81,
    text: 'AI systems require careful evaluation of outputs. Confidence scoring helps identify uncertain predictions. Hallucination detection and source verification prevent misinformation.'
  }
];

return {
  question: question,
  embeddingModel: embeddingModel,
  embeddingDimension: embeddingDimension,
  retrievalResults: mockDocuments,
  resultCount: mockDocuments.length
};

// Stage 4: Build RAG prompt with retrieved context
const { question, retrievalResults, embeddingModel, embeddingDimension } = $input.first().json;
const results = retrievalResults || [];

const contextText = results
  .map((r, i) => `[Source ${i + 1}] (Similarity: ${(r.similarity * 100).toFixed(1)}%)\n${r.text}`)
  .join('\n\n');

const systemPrompt = `You are an expert AI assistant specializing in architecture, automation, and AI systems. You have access to internal documentation and must always cite your sources using [Source N] format. Answer ONLY from the provided context. If the context does not contain the answer, say so.`;

const userPrompt = `Based on the following documentation:\n\n${contextText}\n\nQuestion: ${question}\n\nProvide a detailed answer citing specific sections.`;

return {
  systemPrompt: systemPrompt,
  userPrompt: userPrompt,
  sources: results,
  question: question,
  embeddingModel: embeddingModel,
  embeddingDimension: embeddingDimension
};

// Stage 5: Generate answer via LM Studio (google/gemma-4-12b)
const LM_STUDIO_URL = 'http://127.0.0.1:1234';
const LLM_MODEL = 'google/gemma-4-12b';

const { systemPrompt, userPrompt, sources, question, embeddingModel, embeddingDimension } = $input.first().json;

let res;
try {
  res = await this.helpers.httpRequest({
    method: 'POST',
    url: `${LM_STUDIO_URL}/v1/chat/completions`,
    body: {
      model: LLM_MODEL,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      temperature: 0.3,
      max_tokens: 2048
    },
    json: true,
    timeout: 180000
  });
} catch (error) {
  throw new Error(`LM Studio chat call failed: ${error.message}. Check LM Studio is running on ${LM_STUDIO_URL} with '${LLM_MODEL}' loaded.`);
}

const choice = res && res.choices && res.choices[0];
const message = choice && choice.message;
const answer = message && message.content;

// Gemma 4-12B is a reasoning model: it thinks in reasoning_content first,
// then writes the final answer to content. If max_tokens is exhausted
// mid-reasoning, content comes back empty with finish_reason 'length'.
if (!answer || answer.trim().length === 0) {
  if (choice && choice.finish_reason === 'length') {
    throw new Error(`Token budget exhausted during reasoning (finish_reason: length). Increase max_tokens above 2048.`);
  }
  throw new Error(`LLM returned an empty response. Verify model id '${LLM_MODEL}' matches what LM Studio shows.`);
}

// Pass sources + question through so Format Response can build citations
return {
  question: question,
  answer: answer.trim(),
  sources: sources,
  llmModel: LLM_MODEL,
  embeddingModel: embeddingModel,
  embeddingDimension: embeddingDimension,
  usage: res.usage || null
};

// Stage 6: Format final response with citations and metadata
const { question, answer, sources, llmModel, embeddingModel, embeddingDimension, usage } = $input.first().json;
const results = sources || [];

return {
  status: 'success',
  question: question,
  answer: answer,
  citations: results.map((s, i) => ({
    sourceId: i + 1,
    chunkId: s.chunkId,
    similarity: s.similarity,
    preview: s.text.substring(0, 150) + '...'
  })),
  metadata: {
    generatedAt: new Date().toISOString(),
    embeddingModel: embeddingModel,
    embeddingDimension: embeddingDimension,
    llmModel: llmModel,
    provider: 'LM Studio (local, OpenAI-compatible API)',
    tokenUsage: usage,
    retrievalCount: results.length,
    pipeline: 'RAG (Retrieval-Augmented Generation) - Self-Hosted',
    version: '2.1',
    costEstimate: 'Free (local models)'
  }
};
